import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { CreditCard, Users, AlertTriangle, TrendingUp, Calendar, ShoppingCart, DollarSign } from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    totalEmAberto: 0,
    parcelasFuturas: 0,
    maiorParcelaMes: 0,
    totalGeral: 0,
    qtdComprasMes: 0,
    gastosPorPessoa: {}
  });

  const hoje = new Date();
  const mesAtual = hoje.getMonth();
  const anoAtual = hoje.getFullYear();

  useEffect(() => {
    async function carregarIndicadores() {
      const { data } = await supabase.from('compras').select('*');
      if (!data) return;

      let totalMes = 0;
      let totalEmAberto = 0;
      let parcelasFuturas = 0;
      let maiorParcelaMes = 0;
      let totalGeral = 0;
      let qtdComprasMes = 0;
      let gastosPorPessoa = {};

      data.forEach(item => {
        const valorTotal = parseFloat(item.valor_total);
        const numParcelas = item.num_parcelas || 1;
        const valorParcela = valorTotal / numParcelas;
        const dataCompra = new Date(item.data_compra);
        const responsavel = item.responsavel || 'Indefinido';

        totalGeral += valorTotal;

        gastosPorPessoa[responsavel] = (gastosPorPessoa[responsavel] || 0) + valorTotal;

        if (dataCompra.getMonth() === mesAtual && dataCompra.getFullYear() === anoAtual) {
          qtdComprasMes++;
        }

        for (let i = 0; i < numParcelas; i++) {
          const dataParcela = new Date(dataCompra.getFullYear(), dataCompra.getMonth() + i, 1);

          if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
            totalMes += valorParcela;
            if (valorParcela > maiorParcelaMes) {
              maiorParcelaMes = valorParcela;
            }
          }

          if (dataParcela >= new Date(anoAtual, mesAtual, 1)) {
            totalEmAberto += valorParcela;
            parcelasFuturas++;
          }
        }
      });

      setStats({
        totalMes,
        totalEmAberto,
        parcelasFuturas,
        maiorParcelaMes,
        totalGeral,
        qtdComprasMes,
        gastosPorPessoa
      });
    }

    carregarIndicadores();
  }, []);

  const formatMoney = (v) =>
    `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in">

      {/* ================= PAINEL GERENCIAL ================= */}
      <h2 style={{ marginBottom: '20px' }}>Painel Gerencial</h2>

      <div style={gridStyle}>
        <Card title="Valor a pagar no mês" icon={<Calendar size={18} />} value={formatMoney(stats.totalMes)} />
        <Card title="Total em aberto" icon={<DollarSign size={18} />} value={formatMoney(stats.totalEmAberto)} />
        <Card title="Parcelas futuras" icon={<CreditCard size={18} />} value={stats.parcelasFuturas} />
        <Card title="Compras no mês" icon={<ShoppingCart size={18} />} value={stats.qtdComprasMes} />
        <Card title="Maior parcela do mês" icon={<AlertTriangle size={18} />} value={formatMoney(stats.maiorParcelaMes)} />
        <Card title="Total histórico" icon={<TrendingUp size={18} />} value={formatMoney(stats.totalGeral)} highlight />
      </div>

      {/* ================= GESTÃO POR PESSOA ================= */}
      <h2 style={{ margin: '40px 0 20px 0' }}>Gestão por Pessoa</h2>

      <div style={gridStyle}>
        {Object.entries(stats.gastosPorPessoa)
          .sort((a, b) => b[1] - a[1])
          .map(([nome, valor]) => {
            const percentual = stats.totalGeral
              ? ((valor / stats.totalGeral) * 100).toFixed(1)
              : 0;

            return (
              <div key={nome} className="card" style={{ padding: '20px' }}>
                <div style={{ fontWeight: 600, marginBottom: '10px' }}>{nome}</div>
                <div style={{ fontSize: '1.6rem', fontWeight: 700 }}>
                  {formatMoney(valor)}
                </div>
                <div style={{ fontSize: '0.85rem', opacity: 0.6 }}>
                  {percentual}% do total geral
                </div>
              </div>
            );
          })}
      </div>

    </div>
  );
};

/* COMPONENTE CARD */
const Card = ({ title, icon, value, highlight }) => (
  <div
    className="card"
    style={{
      padding: '20px',
      background: highlight
        ? 'linear-gradient(135deg, var(--primary), var(--secondary))'
        : undefined,
      color: highlight ? 'white' : undefined
    }}
  >
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', opacity: 0.7 }}>
      {icon}
      {title.toUpperCase()}
    </div>

    <div style={{ fontSize: '1.8rem', fontWeight: 700, marginTop: '12px' }}>
      {value}
    </div>
  </div>
);

const gridStyle = {
  display: 'grid',
  gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
  gap: '20px'
};

export default Dashboard;
